// ============================================================
// InitCore v1.0 — Normalización central
// Recibe el payload parcial que envía un adapter y:
//   1. Genera message_id (UUID v4)
//   2. Genera user_id = sha256(channel + _user_identifier)
//   3. Sanitiza HTML del texto (elimina tags, normaliza entidades)
//   4. Trunca a 5000 chars (doble seguro, los adapters ya truncan)
//   5. Detecta idioma si no viene (heurística simple)
//   6. Calcula content_hash = sha256(channel + user_id + text) para dedupe
// ============================================================

const crypto = require('crypto');

const input = $input.first().json;

function sha256(s) {
  return crypto.createHash('sha256').update(String(s), 'utf-8').digest('hex');
}

function uuidv4() {
  return crypto.randomUUID();
}

// ---- Sanitizar HTML ----
function stripHtml(html) {
  if (!html) return '';
  return String(html)
    // Eliminar scripts y styles enteros
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    // Eliminar cualquier tag
    .replace(/<\/?[^>]+>/g, '')
    // Decodificar entidades básicas
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&apos;/gi, "'")
    // Colapsar espacios
    .replace(/\s+/g, ' ')
    .trim();
}

// ---- Heurística simple de idioma (suficiente para español/inglés) ----
function detectLanguage(text) {
  if (!text) return 'es';
  const t = text.toLowerCase();
  const esMarkers = /\b(que|los|las|una|uno|por|para|con|sin|pero|cuando|donde|gracias|hola|buenos|buenas|necesito|quiero|puedes)\b/;
  const enMarkers = /\b(the|and|you|are|with|from|what|when|where|thanks|hello|hi|need|want|can)\b/;
  const es = (t.match(esMarkers) || []).length;
  const en = (t.match(enMarkers) || []).length;
  if (en > es) return 'en';
  return 'es';
}

// ---- Construir objeto normalizado ----
const channel = input.channel || 'unknown';
const userIdentifier = input._user_identifier || input.context?.email || input.context?.phone || 'anonymous';
const user_id = sha256(channel + ':' + userIdentifier);
const message_id = uuidv4();

const rawText = input.message?.text || '';
const cleanText = stripHtml(rawText).substring(0, 5000);

const language = (input.context?.language && input.context.language !== '')
  ? input.context.language
  : detectLanguage(cleanText);

const content_hash = sha256(channel + ':' + user_id + ':' + cleanText);

const payload = {
  message_id,
  user_id,
  channel,
  message: {
    text: cleanText,
    media: Array.isArray(input.message?.media) ? input.message.media : []
  },
  timestamp: input.timestamp || new Date().toISOString(),
  context: {
    name: input.context?.name || '',
    email: input.context?.email || '',
    phone: input.context?.phone || '',
    language
  },
  metadata: {
    ...(input.metadata || {}),
    normalized_at: new Date().toISOString(),
    core_version: '1.0.0'
  },
  status: input.status || 'pending',
  content_hash
};

return [{ json: payload }];

// Combina el resultado del SELECT con el payload original
const payload = $('Normalizar payload').first().json;
const dupCheck = $input.first().json;
const isDuplicate = Boolean(dupCheck && (dupCheck.exists === 1 || dupCheck.exists === '1'));
return [{ json: { ...payload, _is_duplicate: isDuplicate } }];

// Rama duplicado — no inserta, devuelve status skipped
const p = $input.first().json;
return [{ json: { message_id: p.message_id, channel: p.channel, status: 'duplicate_24h_skipped', content_hash: p.content_hash } }];

// Devuelve OK al adapter
const payload = $('Unir resultado dedupe').first().json;
return [{ json: { message_id: payload.message_id, user_id: payload.user_id, channel: payload.channel, status: 'persisted' } }];
